import{useState,useEffect,useCallback}from"react";
async function getWeather(a,b){const r=await fetch("https://api.open-meteo.com/v1/forecast?latitude="+a+"&longitude="+b+"&current=temperature_2m,wind_speed_10m,wind_direction_10m,wind_gusts_10m,uv_index,apparent_temperature&hourly=wind_speed_10m,wind_gusts_10m&forecast_days=2&wind_speed_unit=kn&timezone=auto");if(!r.ok)throw new Error("err "+r.status);return r.json();}
async function getMarine(a,b){try{const r=await fetch("https://marine-api.open-meteo.com/v1/marine?latitude="+a+"&longitude="+b+"&current=wave_height,wave_period,swell_wave_height,sea_surface_temperature&hourly=wave_height&timezone=auto&forecast_days=2");if(!r.ok)return null;return r.json();}catch{return null;}}
const S=[{id:43,name:"Tarifa",country:"Spain",lat:36,lng:-5.65,region:"Europe"},{id:5693,name:"Maui",country:"Hawaii USA",lat:20.906,lng:-156.422,region:"Pacific"},{id:309513,name:"Hossegor",country:"France",lat:43.658,lng:-1.447,region:"Europe"},{id:75856,name:"Nazare",country:"Portugal",lat:39.6,lng:-9.075,region:"Europe"},{id:4239,name:"Cape Town",country:"S.Africa",lat:-33.917,lng:18.404,region:"Africa"},{id:26,name:"Essaouira",country:"Morocco",lat:31.502,lng:-9.764,region:"Africa"},{id:15278,name:"Dakhla",country:"Morocco",lat:23.917,lng:-15.774,region:"Africa"},{id:782987,name:"Siargao",country:"Philippines",lat:9.792,lng:126.162,region:"Asia"},{id:231,name:"Uluwatu",country:"Bali",lat:-8.83,lng:115.09,region:"Asia"},{id:158,name:"Canggu",country:"Bali",lat:-8.65,lng:115.13,region:"Asia"},{id:211,name:"Ericeira",country:"Portugal",lat:38.963,lng:-9.416,region:"Europe"},{id:203944,name:"Sagres",country:"Portugal",lat:37.014,lng:-8.938,region:"Europe"},{id:15604,name:"Cabarete",country:"Dom.Republic",lat:19.751,lng:-70.412,region:"Caribbean"},{id:15025,name:"Aruba",country:"Aruba",lat:12.57,lng:-70.06,region:"Caribbean"},{id:50613,name:"Zanzibar",country:"Tanzania",lat:-5.95,lng:39.45,region:"Indian"},{id:49045,name:"El Gouna",country:"Egypt",lat:27.4,lng:33.68,region:"Indian"},{id:456789,name:"El Medano",country:"Tenerife",lat:28.047,lng:-16.534,region:"Atlantic"},{id:567890,name:"Corralejo",country:"Fuerteventura",lat:28.728,lng:-13.867,region:"Atlantic"},{id:15605,name:"Jericoacoara",country:"Brazil",lat:-2.9,lng:-40.51,region:"S.America"},{id:990123,name:"Rio de Janeiro",country:"Brazil",lat:-22.987,lng:-43.192,region:"S.America"}];
function dist(a1,o1,a2,o2){const R=6371,da=(a2-a1)*Math.PI/180,doo=(o2-o1)*Math.PI/180,a=Math.sin(da/2)**2+Math.cos(a1*Math.PI/180)*Math.cos(a2*Math.PI/180)*Math.sin(doo/2)**2;return R*2*Math.atan2(Math.sqrt(a),Math.sqrt(1-a));}
function search(q){if(!q)return[];const l=q.toLowerCase();return S.map(s=>({...s,sc:(s.name.toLowerCase().includes(l)?2:0)+(s.country.toLowerCase().includes(l)?1:0)})).filter(s=>s.sc>0).sort((a,b)=>b.sc-a.sc).slice(0,6);}
function nearest(la,lo){return S.map(s=>({...s,d:dist(la,lo,s.lat,s.lng)})).sort((a,b)=>a.d-b.d).slice(0,6);}
const WD=["N","NNE","NE","ENE","E","ESE","SE","SSE","S","SSW","SW","WSW","W","WNW","NW","NNW"];
const wetsuit=t=>!t||t>=24?"Boardshorts":t>=21?"1-2mm Shorty":t>=18?"2mm Shorty":t>=15?"3/2mm Fullsuit":t>=12?"4/3mm Fullsuit":"5mm+ Drysuit";
const wcolor=t=>!t||t>=24?"#f97316":t>=18?"#eab308":t>=15?"#0ea5e9":"#6366f1";
const kite=w=>w<8?"Too light":w<12?"17-19m":w<16?"14-17m":w<20?"12-14m":w<25?"10-12m":w<30?"9-10m":"7-9m";
const sail=w=>w<8?"8-10m":w<14?"6.5-8m":w<18?"5.5-6.5m":w<24?"4.5-5.5m":"3.5-4.5m";
function safety(wind,wave,sport,level){const ex=level==="expert"||level==="advanced",bg=level==="beginner";const L={surf:{minWave:0.3,maxWave:ex?6:bg?1.5:3,maxWind:25},kite:{minWind:8,maxWind:ex?45:bg?20:35},windsurf:{minWind:8,maxWind:ex?50:bg?20:40},kayak:{maxWind:bg?15:25},sup:{maxWind:bg?12:20},sail:{minWind:5,maxWind:ex?40:30},fishing:{maxWind:25}}[sport]||{};let sc=100;const w=[];if(L.minWind&&wind<L.minWind){sc-=30;w.push("Wind too light");}if(L.maxWind&&wind>L.maxWind){sc-=40;w.push("Too strong for "+level);}if(L.minWave&&wave<L.minWave){sc-=20;w.push("Waves too small");}if(L.maxWave&&wave>L.maxWave){sc-=40;w.push("Waves too big");}return{status:sc<=30?"NO-GO":sc<=65?"CAUTION":"GO",score:Math.max(0,sc),warnings:w};}
function Compass({deg,speed}){const dir=WD[Math.round(deg/22.5)%16];return(<div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6}}><svg width="70" height="70" viewBox="0 0 72 72"><circle cx="36" cy="36" r="33" fill="none" stroke="#334155" strokeWidth="1.5"/><circle cx="36" cy="36" r="26" fill="rgba(14,165,233,0.06)" stroke="#334155" strokeWidth="1"/>{["N","E","S","W"].map((d,i)=>(<text key={d} x={36+28*Math.sin(i*Math.PI/2)} y={36-28*Math.cos(i*Math.PI/2)+3.5} textAnchor="middle" fontSize="8" fill="#64748b">{d}</text>))}<g transform={"rotate("+deg+",36,36)"}><polygon points="36,10 39,30 36,27 33,30" fill="#0ea5e9"/><polygon points="36,62 39,42 36,45 33,42" fill="#0ea5e9" opacity="0.3"/></g><circle cx="36" cy="36" r="4" fill="white" stroke="#0ea5e9" strokeWidth="2"/></svg><div style={{textAlign:"center"}}><div style={{fontSize:28,fontWeight:900,color:"#0ea5e9",lineHeight:1}}>{speed}</div><div style={{fontSize:8,color:"#64748b"}}>{dir} KTS</div></div></div>);}
function Badge({status,score,warnings}){const c={GO:{bg:"#dcfce7",c:"#16a34a",b:"#86efac"},CAUTION:{bg:"#fef9c3",c:"#ca8a04",b:"#fde047"},"NO-GO":{bg:"#fee2e2",c:"#dc2626",b:"#fca5a5"}}[status]||{bg:"#f1f5f9",c:"#64748b",b:"#e2e8f0"};return(<div style={{background:c.bg,border:"2px solid "+c.b,borderRadius:14,padding:"13px 16px"}}><div style={{display:"flex",alignItems:"center",gap:10,marginBottom:warnings.length?6:0}}><div style={{fontSize:18,fontWeight:900,color:c.c}}>{status}</div><div style={{fontSize:9,color:c.c,opacity:0.7}}>SCORE {score}/100</div></div>{warnings.map((w,i)=><div key={i} style={{fontSize:11,color:c.c}}>· {w}</div>)}</div>);}
function Tile({label,value,unit,sub,color,T}){return(<div style={{background:T.card,border:"1.5px solid "+T.border,borderRadius:12,padding:"12px 14px"}}><div style={{fontSize:8,color:T.sub,letterSpacing:2,marginBottom:4}}>{label}</div><div style={{display:"flex",alignItems:"flex-end",gap:3}}><span style={{fontSize:20,fontWeight:800,color:color||T.text,lineHeight:1}}>{value}</span>{unit&&<span style={{fontSize:10,color:T.sub,marginBottom:1}}>{unit}</span>}</div>{sub&&<div style={{fontSize:10,color:T.sub,marginTop:3}}>{sub}</div>}</div>);}
function Strip({hourly,waveH,T}){if(!hourly?.time)return null;const now=new Date();const items=hourly.time.map((t,i)=>({t:new Date(t),w:hourly.wind_speed_10m?.[i],wave:waveH?.[i]})).filter(x=>x.t>=now).slice(0,12);return(<div style={{marginBottom:8}}><div style={{fontSize:8,color:T.sub,letterSpacing:3,marginBottom:8}}>24H FORECAST</div><div style={{display:"flex",gap:5,overflowX:"auto",paddingBottom:4}}>{items.map((x,i)=>{const n=i===0;return(<div key={i} style={{flexShrink:0,width:50,background:n?"#0ea5e9":T.card,border:"1.5px solid "+(n?"#0ea5e9":T.border),borderRadius:9,padding:"6px 4px",textAlign:"center"}}><div style={{fontSize:7,color:n?"rgba(255,255,255,0.7)":T.sub}}>{n?"NOW":x.t.getHours()+"h"}</div><div style={{fontSize:16,fontWeight:800,color:n?"white":T.text}}>{Math.round(x.w||0)}</div><div style={{fontSize:6,color:n?"rgba(255,255,255,0.6)":T.sub}}>kts</div>{x.wave!=null&&<div style={{fontSize:7,color:n?"rgba(255,255,255,0.8)":"#0ea5e9"}}>{x.wave.toFixed(1)}m</div>}</div>);})}</div></div>);}
function SpotCard({s,onClick,T}){return(<div onClick={onClick} style={{background:T.card,border:"1.5px solid "+T.border,borderRadius:14,padding:"14px 16px",marginBottom:10,cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center",transition:"border-color .15s"}} onMouseEnter={e=>e.currentTarget.style.borderColor="#0ea5e9"} onMouseLeave={e=>e.currentTarget.style.borderColor=T.border}><div><div style={{fontWeight:800,fontSize:15,color:T.text}}>{s.name}</div><div style={{fontSize:12,color:T.sub,marginTop:2}}>{s.country} · {s.region}</div></div><div style={{color:"#0ea5e9",fontSize:16,fontWeight:700}}>→</div></div>);}
const SPORTS=["surf","kite","windsurf","kayak","sup","sail","fishing"];
const LEVELS=["beginner","advanced","expert"];
export default function App(){
  const[dark,setDark]=useState(()=>window.matchMedia("(prefers-color-scheme: dark)").matches);
  const[view,setView]=useState("home");
  const[geo,setGeo]=useState(null);
  const[nearby,setNearby]=useState([]);
  const[query,setQuery]=useState("");
  const[spot,setSpot]=useState(null);
  const[data,setData]=useState(null);
  const[loading,setLoading]=useState(false);
  const[sport,setSport]=useState("surf");
  const[level,setLevel]=useState("advanced");
  useEffect(()=>{const mq=window.matchMedia("(prefers-color-scheme: dark)");const fn=e=>setDark(e.matches);mq.addEventListener("change",fn);return()=>mq.removeEventListener("change",fn);},[]);
  useEffect(()=>{if(!navigator.geolocation){setGeo("denied");return;}navigator.geolocation.getCurrentPosition(p=>{const{latitude:la,longitude:lo}=p.coords;setGeo({la,lo});setNearby(nearest(la,lo));},()=>setGeo("denied"));},[]);
  const pick=useCallback(async s=>{setSpot(s);setView("spot");setData(null);setLoading(true);try{const[w,m]=await Promise.all([getWeather(s.lat,s.lng),getMarine(s.lat,s.lng)]);setData({w,m});}catch{setData({err:true});}setLoading(false);},[]);
  const T={bg:dark?"#0f172a":"#f8fafc",card:dark?"#1e293b":"#ffffff",border:dark?"#334155":"#e2e8f0",text:dark?"#f1f5f9":"#0f172a",sub:dark?"#94a3b8":"#64748b"};
  const wd=data?.w,wm=data?.m;
  const wind=Math.round(wd?.current?.wind_speed_10m||0);
  const gust=Math.round(wd?.current?.wind_gusts_10m||0);
  const wdir=wd?.current?.wind_direction_10m||0;
  const wave=wm?.current?.wave_height||0;
  const period=wm?.current?.wave_period||0;
  const swell=wm?.current?.swell_wave_height||0;
  const sst=wm?.current?.sea_surface_temperature??null;
  const airT=Math.round(wd?.current?.temperature_2m||0);
  const feelT=Math.round(wd?.current?.apparent_temperature||0);
  const uv=wd?.current?.uv_index||0;
  const sf=safety(wind,wave,sport,level);
  const srList=query?search(query):[];
  const listSpots=geo&&geo!=="denied"?nearby:S;
  return(
    <div style={{minHeight:"100vh",background:T.bg,color:T.text,fontFamily:"system-ui,-apple-system,sans-serif"}}>
      <div style={{padding:"16px 20px",borderBottom:"1.5px solid "+T.border,display:"flex",alignItems:"center",gap:12,position:"sticky",top:0,background:T.bg,zIndex:10,backdropFilter:"blur(8px)"}}>
        {view==="spot"&&<button onClick={()=>{setView("home");setQuery("");}} style={{background:"none",border:"none",color:"#0ea5e9",fontSize:20,cursor:"pointer",padding:0,lineHeight:1,fontWeight:700}}>←</button>}
        <div style={{fontSize:20,fontWeight:900,color:"#0ea5e9",letterSpacing:-0.5}}>WaveIQ</div>
        {view==="spot"&&spot&&<div style={{fontSize:13,fontWeight:600,color:T.sub,marginLeft:2}}>{spot.name}, {spot.country}</div>}
      </div>
      {view==="home"&&(
        <div style={{padding:"20px 16px",maxWidth:480,margin:"0 auto"}}>
          <input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Search spots…" style={{width:"100%",padding:"12px 14px",borderRadius:12,border:"1.5px solid "+T.border,background:T.card,color:T.text,fontSize:15,boxSizing:"border-box",outline:"none",marginBottom:20}}/>
          {srList.length>0
            ?srList.map(s=><SpotCard key={s.id} s={s} onClick={()=>pick(s)} T={T}/>)
            :<>
              <div style={{fontSize:10,letterSpacing:3,color:T.sub,marginBottom:12}}>{geo===null?"DETECTING YOUR LOCATION…":geo==="denied"?"ALL SPOTS":"NEAREST SPOTS"}</div>
              {listSpots.map(s=><SpotCard key={s.id} s={s} onClick={()=>pick(s)} T={T}/>)}
            </>
          }
        </div>
      )}
      {view==="spot"&&(
        <div style={{padding:"16px",maxWidth:480,margin:"0 auto"}}>
          <div style={{display:"flex",gap:6,overflowX:"auto",marginBottom:14,paddingBottom:2}}>
            {SPORTS.map(sp=><button key={sp} onClick={()=>setSport(sp)} style={{flexShrink:0,padding:"7px 14px",borderRadius:20,border:"none",background:sport===sp?"#0ea5e9":T.card,color:sport===sp?"white":T.sub,fontWeight:700,fontSize:12,cursor:"pointer",textTransform:"capitalize"}}>{sp==="sup"?"SUP":sp}</button>)}
          </div>
          <div style={{display:"flex",gap:6,marginBottom:18}}>
            {LEVELS.map(lv=><button key={lv} onClick={()=>setLevel(lv)} style={{flex:1,padding:"7px 0",borderRadius:10,border:"1.5px solid "+(level===lv?"#0ea5e9":T.border),background:level===lv?"#0ea5e9":T.card,color:level===lv?"white":T.sub,fontWeight:700,fontSize:11,cursor:"pointer",textTransform:"capitalize"}}>{lv}</button>)}
          </div>
          {loading&&<div style={{textAlign:"center",padding:60,color:T.sub,fontSize:14}}>Loading conditions…</div>}
          {data?.err&&<div style={{textAlign:"center",padding:60,color:"#ef4444",fontSize:14}}>Failed to load data. Check your connection.</div>}
          {data&&!data.err&&<>
            <div style={{marginBottom:14}}><Badge status={sf.status} score={sf.score} warnings={sf.warnings}/></div>
            <div style={{display:"flex",gap:10,marginBottom:10}}>
              <div style={{flex:1,background:T.card,border:"1.5px solid "+T.border,borderRadius:12,padding:14,display:"flex",justifyContent:"center",alignItems:"center"}}><Compass deg={wdir} speed={wind}/></div>
              <div style={{flex:1,display:"flex",flexDirection:"column",gap:8}}>
                <Tile label="GUSTS" value={gust} unit="kts" T={T}/>
                <Tile label="WAVE" value={wave.toFixed(1)} unit="m" color="#0ea5e9" T={T}/>
                <Tile label="PERIOD" value={Math.round(period)} unit="s" T={T}/>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
              <Tile label="SWELL" value={swell.toFixed(1)} unit="m" T={T}/>
              <Tile label="AIR TEMP" value={airT} unit="°C" sub={"Feels "+feelT+"°"} T={T}/>
              <Tile label="UV INDEX" value={uv.toFixed(1)} color={uv>7?"#ef4444":uv>3?"#eab308":"#22c55e"} T={T}/>
              {sst!=null&&<Tile label="WATER TEMP" value={Math.round(sst)} unit="°C" sub={wetsuit(sst)} color={wcolor(sst)} T={T}/>}
            </div>
            {(sport==="kite"||sport==="windsurf")&&<div style={{background:T.card,border:"1.5px solid "+T.border,borderRadius:12,padding:"12px 14px",marginBottom:10}}><div style={{fontSize:8,letterSpacing:3,color:T.sub,marginBottom:4}}>RECOMMENDED GEAR</div><div style={{fontSize:15,fontWeight:800,color:"#0ea5e9"}}>{sport==="kite"?kite(wind)+" kite":sail(wind)+" sail"}</div></div>}
            <Strip hourly={wd?.hourly} waveH={wm?.hourly?.wave_height} T={T}/>
          </>}
        </div>
      )}
    </div>
  );
}
